mapper.select:
select *
from biz.settlement_batch
where tenant_id = #{tenantId}
  and batch_no = #{batchNo}

select *
from biz.settlement_detail
where tenant_id = #{tenantId}
  and batch_id = #{batchId}
order by id asc

mapper.update:
update biz.settlement_batch
set batch_status = 'EXPORTED',
    updated_at = current_timestamp
where tenant_id = #{tenantId}
  and id = #{batchId}

update biz.settlement_detail
set exported_version = greatest(exported_version, #{exportVersion}),
    settlement_status = case
        when settlement_status in ('READY', 'SETTLED') then 'EXPORTED'
        else settlement_status
    end,
    source_trace_id = coalesce(#{traceId}, source_trace_id),
    updated_at = current_timestamp
where tenant_id = #{tenantId}
  and batch_id = #{batchId}
